class RateLimitInterceptor(ServerInterceptor):
    """Simple rate limiting interceptor."""

    def __init__(self, max_requests_per_second: int = 100):
        self._max_rps = max_requests_per_second
        self._request_counts: dict[str, list[float]] = {}

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        now = time.time()

        if method not in self._request_counts:
            self._request_counts[method] = []

        # Clean old entries
        self._request_counts[method] = [
            t for t in self._request_counts[method] if now - t < 1.0
        ]

        if len(self._request_counts[method]) >= self._max_rps:
            logger.warning(f"Rate limit exceeded for {method}")
            return self._rate_limited_handler()

        self._request_counts[method].append(now)
        return continuation(handler_call_details)

    def _rate_limited_handler(self):
        def _handler(request, context):
            context.abort(
                grpc.StatusCode.RESOURCE_EXHAUSTED,
                "Rate limit exceeded. Please retry later.",
            )

        return grpc.unary_unary_rpc_method_handler(_handler)


